(game "Vivid Thistle Moose — Step 3 (Moose charge captures)"
    (players 2)
    (equipment
        (board (square 9))
    )

    (rules
        (play
            (repeat (P1 P2)
                (place
                    (destination
                        (and
                            empty
                            (not (adjacent (prev_move opponent)))
                        )
                    )
                    (effects
                        (capture (custodial 1) increment_score:true)
                    )
                )
            )
        )

        (end
            (if (line 4) (mover win))
            (if (>= (score mover) 5) (mover win))
            (if (full_board) (draw))
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

(game "Vivid Thistle Moose — Step 4 (Vivid hazard + forced pass)"
    (players 2)
    (equipment
        (board (square 9))
    )

    (rules
        (play
            (repeat (P1 P2)
                (place
                    (destination
                        (and
                            empty
                            (not (adjacent (prev_move opponent)))
                        )
                    )
                    (effects
                        (capture (custodial 1) increment_score:true)
                    )
                )
                (force_pass)
            )
        )

        (end
            (if (and (line 3 exact:true) (not (line 4))) (mover lose))
            (if (line 4) (mover win))
            (if (>= (score mover) 5) (mover win))
            (if (passed both) (by_score))
            (if (full_board) (draw))
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

