(game "Glowweave v1: Trails"
    (players 2)
    (equipment
        (board (square 11))
    )

    (rules
        (play
            (once_through (P1)
                (place (destination empty))
            )
            (once_through (P2)
                (place (destination empty))
            )
            (repeat (P1 P2)
                (place
                    (destination (and
                        empty
                        (adjacent (prev_move mover))
                    ))
                )
            )
        )

        (end
            (if (line 4) (mover win))
            (if (full_board) (draw))
        )
    )

    (rendering
        (color P1 black)
        (color P2 white)
    )
)

(game "Glowweave v2: Tension & Captures"
    (players 2)
    (equipment
        (board (square 11))
    )

    (rules
        (play
            (once_through (P1)
                (place (destination empty))
            )
            (once_through (P2)
                (place (destination empty))
            )
            (repeat (P1 P2)
                (place
                    (destination (and
                        empty
                        (adjacent (prev_move mover))
                        (not (adjacent (prev_move opponent) direction:orthogonal))
                    ))
                    (effects
                        (capture (custodial 2 orientation:orthogonal) increment_score:true)
                    )
                )
            )
        )

        (end
            (if (line 4) (mover win))
            (if (>= (score mover) 6) (mover win))
            (if (full_board) (draw))
        )
    )

    (rendering
        (color P1 black)
        (color P2 white)
    )
)

(game "Glowweave v3: Edge Loom & Overgrowth Ban"
    (players 2)
    (equipment
        (board (square 11))
    )

    (rules
        (play
            (once_through (P1)
                (place (destination empty))
            )
            (once_through (P2)
                (place (destination empty))
            )
            (repeat (P1 P2)
                (place
                    (destination (and
                        empty
                        (adjacent (prev_move mover))
                        (not (adjacent (prev_move opponent) direction:orthogonal))
                    ))
                    (result
                        (not (line 5))
                    )
                    (effects
                        (capture (custodial 2 orientation:orthogonal) increment_score:true)
                    )
                )
                (force_pass)
            )
        )

        (end
            (if (line 4 exact:true) (mover win))
            (if (>= (score mover) 6) (mover win))
            (if (and (>= (connected ((edge top) (edge bottom))) 2) (mover_is P1)) (mover win))
            (if (and (>= (connected ((edge left) (edge right))) 2) (mover_is P2)) (mover win))
            (if (full_board) (draw))
        )
    )

    (rendering
        (color P1 black)
        (color P2 white)
    )
)
